class Worker {
    private volatile boolean flag = false;

    public void stop()  { flag = true; }
    public boolean isRunning() { return !flag; }
}

// Thread A:
worker.stop();              // writes flag = true

// Thread B:
if (worker.isRunning()) {   // reads flag
    doWork();
